import type { CatInsert, CatMode, CatOwnerView, CatPublicView } from "../types.js";

/**
 * Insert a new cat.
 * public_id must be generated by the TypeScript ID generator before calling
 * this function. Throws a D1 UNIQUE constraint error if public_id is already
 * taken — the caller must catch and retry with a freshly generated public_id.
 * Internal cat.id is never returned; use public_id for all subsequent lookups.
 */
export async function insertCat(
  db: D1Database,
  data: CatInsert,
): Promise<void> {
  await db
    .prepare(
      `INSERT INTO cats (public_id, owner_id, name, country_code, photo_r2_key, current_mode, sex, birth_date, color_markings, breed_mix, weight, notes)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
    )
    .bind(
      data.public_id,
      data.owner_id,
      data.name,
      data.country_code,
      data.photo_r2_key ?? null,
      data.current_mode ?? "active",
      data.sex ?? null,
      data.birth_date ?? null,
      data.color_markings ?? null,
      data.breed_mix ?? null,
      data.weight ?? null,
      data.notes ?? null,
    )
    .run();
}

/**
 * Look up a cat by public_id, verified to belong to the given owner.
 * Returns null if the cat does not exist or is not owned by this owner.
 * Includes notes (private owner-only field).
 */
export async function getCatForOwner(
  db: D1Database,
  publicId: string,
  ownerId: number,
): Promise<CatOwnerView | null> {
  return db
    .prepare(
      `SELECT public_id, name, country_code, photo_r2_key, current_mode,
              sex, birth_date, color_markings, breed_mix, weight, notes
       FROM cats
       WHERE public_id = ? AND owner_id = ?`,
    )
    .bind(publicId, ownerId)
    .first<CatOwnerView>();
}

/**
 * Public cat lookup — used on every QR scan.
 * Returns only whitelisted public columns. No internal id, no owner_id,
 * no cartilla data, no contact settings (fetch separately if needed for mode).
 * Does NOT include notes (private to owner).
 * Excludes soft-deleted cats.
 * Returns null if no cat with that public_id exists.
 */
export async function getCatPublicProfile(
  db: D1Database,
  publicId: string,
): Promise<CatPublicView | null> {
  return db
    .prepare(
      `SELECT public_id, name, country_code, photo_r2_key, current_mode,
              sex, birth_date, color_markings, breed_mix, weight
       FROM cats
       WHERE public_id = ? AND deleted_at IS NULL`,
    )
    .bind(publicId)
    .first<CatPublicView>();
}

/**
 * List all cats belonging to an owner (owner dashboard).
 * Returns the same whitelisted public columns as getCatPublicProfile.
 * ownerId is an internal value from the authenticated session — never a URL param.
 * Excludes soft-deleted cats.
 */
export async function listCatsForOwner(
  db: D1Database,
  ownerId: number,
): Promise<CatPublicView[]> {
  const result = await db
    .prepare(
      `SELECT public_id, name, country_code, photo_r2_key, current_mode,
              sex, birth_date, color_markings, breed_mix, weight
       FROM cats
       WHERE owner_id = ? AND deleted_at IS NULL
       ORDER BY created_at ASC`,
    )
    .bind(ownerId)
    .all<CatPublicView>();
  return result.results;
}

/**
 * Update the active mode for a cat.
 * Only succeeds if public_id and owner_id both match, preventing one owner
 * from switching another owner's cat. Returns true if updated, false if the
 * cat was not found or not owned by this owner.
 */
export async function updateCatMode(
  db: D1Database,
  publicId: string,
  ownerId: number,
  mode: CatMode,
): Promise<boolean> {
  const result = await db
    .prepare(
      `UPDATE cats
       SET current_mode = ?
       WHERE public_id = ? AND owner_id = ?`,
    )
    .bind(mode, publicId, ownerId)
    .run();
  return result.meta.changes > 0;
}

/**
 * Update the R2 key for a cat's profile photo.
 * Only succeeds if ownership is confirmed. Returns true if updated.
 */
export async function updateCatPhoto(
  db: D1Database,
  publicId: string,
  ownerId: number,
  photoR2Key: string,
): Promise<boolean> {
  const result = await db
    .prepare(
      `UPDATE cats
       SET photo_r2_key = ?
       WHERE public_id = ? AND owner_id = ?`,
    )
    .bind(photoR2Key, publicId, ownerId)
    .run();
  return result.meta.changes > 0;
}


/**
 * Soft-delete a cat. Sets deleted_at to current timestamp.
 * Ownership enforced: only succeeds if public_id and owner_id both match.
 * Returns true if a row was updated, false if not found or not owned.
 */
export async function softDeleteCat(
  db: D1Database,
  publicId: string,
  ownerId: number,
): Promise<boolean> {
  const result = await db
    .prepare(
      `UPDATE cats
       SET deleted_at = strftime('%Y-%m-%dT%H:%M:%SZ', 'now')
       WHERE public_id = ? AND owner_id = ? AND deleted_at IS NULL`,
    )
    .bind(publicId, ownerId)
    .run();
  return result.meta.changes > 0;
}
